/**
 * @psyforge/timing - High-precision timing system for psychological experiments
 * 
 * Provides microsecond-level timing accuracy using Web Audio API and Performance API
 * for reliable stimulus presentation and response collection in behavioral research.
 */

export {
  PrecisionClock,
  precisionClock,
  type TimingContext,
  type PrecisionTimestamp
} from './PrecisionClock';

export {
  TimingDriftDetector,
  createDriftDetector,
  type DriftMeasurement,
  type DriftStatus
} from './TimingDriftDetector';

export {
  TimingBenchmarkHarness,
  createTimingBenchmark,
  type BenchmarkResults,
  type BenchmarkConfig,
  type HardwareCapabilities
} from './TimingBenchmark';

/**
 * Check if high-precision timing is supported in current environment
 */
export function isTimingSupported(): boolean {
  return !!(
    typeof AudioContext !== 'undefined' &&
    typeof performance !== 'undefined' &&
    typeof performance.now === 'function' &&
    typeof requestAnimationFrame === 'function'
  );
}

/**
 * Get estimated timing precision for current environment
 */
export async function getTimingCapabilities(): Promise<{
  supported: boolean;
  audioContextSupported: boolean;
  performanceSupported: boolean;
  rafSupported: boolean;
  estimatedPrecision: number;
}> {
  const audioContextSupported = typeof AudioContext !== 'undefined';
  const performanceSupported = typeof performance !== 'undefined' && typeof performance.now === 'function';
  const rafSupported = typeof requestAnimationFrame === 'function';
  const supported = audioContextSupported && performanceSupported && rafSupported;

  let estimatedPrecision = 0;

  if (supported) {
    try {
      // Quick precision test
      const samples: number[] = [];
      for (let i = 0; i < 10; i++) {
        const start = performance.now();
        const end = performance.now();
        samples.push(end - start);
      }
      const validSamples = samples.filter(s => s > 0);
      estimatedPrecision = validSamples.length > 0 ? Math.min(...validSamples) * 1000 : Infinity;
    } catch (error) {
      estimatedPrecision = 0;
      throw error;
    }
  }

  return {
    supported,
    audioContextSupported,
    performanceSupported,
    rafSupported,
    estimatedPrecision
  };
}

