// Core device abstractions
export { Device } from './Device';
export type { DeviceCapabilities, DeviceEvent } from './Device';
export { DeviceManager } from './DeviceManager';
export type { DeviceManagerOptions, DeviceType } from './DeviceManager';

// Input devices
export { KeyboardDevice } from './KeyboardDevice';
export type { KeyboardEventData } from './KeyboardDevice';
export { MouseDevice } from './MouseDevice';
export type { MouseEventData } from './MouseDevice';
export { TouchDevice } from './TouchDevice';
export type {
  TouchEventData,
  TouchPoint,
  OrientationEventData,
} from './TouchDevice';

// Audio/video devices
export { AudioDevice } from './AudioDevice';
export type { AudioDeviceInfo, AudioEventData } from './AudioDevice';
export { VideoDevice } from './VideoDevice';
export type { VideoDeviceInfo, VideoEventData } from './VideoDevice';

// Import types for internal use
import { Device } from './Device';
import { DeviceManager, DeviceManagerOptions } from './DeviceManager';
import { KeyboardDevice } from './KeyboardDevice';
import { MouseDevice } from './MouseDevice';
import { TouchDevice } from './TouchDevice';
import { AudioDevice } from './AudioDevice';
import { VideoDevice } from './VideoDevice';

// Helper functions for common device management patterns
export function createDeviceManager(
  clock: import('@psyforge/timing').PrecisionClock,
  options?: DeviceManagerOptions,
): DeviceManager {
  return new DeviceManager(clock, options);
}

export async function detectDeviceCapabilities(
  clock: import('@psyforge/timing').PrecisionClock,
): Promise<{
  keyboard: boolean;
  mouse: boolean;
  touch: boolean;
  audio: boolean;
  video: boolean;
}> {
  const manager = createDeviceManager(clock, { enableAutoDetection: false });
  return await manager.detectAvailableDevices();
}

// Type guards for device instances
export function isKeyboardDevice(device: Device): device is KeyboardDevice {
  return device.deviceType === 'keyboard';
}

export function isMouseDevice(device: Device): device is MouseDevice {
  return device.deviceType === 'mouse';
}

export function isTouchDevice(device: Device): device is TouchDevice {
  return device.deviceType === 'touch';
}

export function isAudioDevice(device: Device): device is AudioDevice {
  return device.deviceType === 'audio';
}

export function isVideoDevice(device: Device): device is VideoDevice {
  return device.deviceType === 'video';
}

