     4→
     5→import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
     6→import { PrecisionClock } from '../src/PrecisionClock.js';
     7→
     8→// Mock Web Audio API for testing
     9→const mockAudioContext = {
    10→  currentTime: 0,
    11→  state: 'running',
    12→  sampleRate: 44100,
    13→  resume: vi.fn().mockResolvedValue(undefined),
    14→  close: vi.fn().mockResolvedValue(undefined),
    15→  createOscillator: vi.fn().mockReturnValue({
    16→    connect: vi.fn(),
    17→    start: vi.fn(),
    18→    stop: vi.fn(),
    19→    onended: null
    20→  }),
    21→  createGain: vi.fn().mockReturnValue({
    22→    connect: vi.fn(),
    23→    gain: { value: 0 }
    24→  }),
    25→  destination: {}
    26→};
    27→
    28→// Mock global APIs
    29→global.AudioContext = vi.fn(() => mockAudioContext as any);
    30→global.performance = {
    31→  now: vi.fn(() => Date.now()),
    32→  timeOrigin: Date.now()
    33→} as any;
    34→global.requestAnimationFrame = vi.fn((callback) => {
    35→  setTimeout(() => callback(performance.now()), 16);
    36→  return 1;
    37→});
    38→global.cancelAnimationFrame = vi.fn();
    39→
    40→describe('PrecisionClock', () => {
    41→  let clock: PrecisionClock;
    42→  
    43→  beforeEach(() => {
    44→    clock = new PrecisionClock();
    45→    vi.clearAllMocks();
    46→  });
    47→  
    48→  afterEach(async () => {
    49→    try {
    50→      await clock.destroy();
    51→    } catch {
    52→      // Ignore cleanup errors in tests
    53→    }
    54→  });
    55→
    56→  describe('initialization', () => {
    57→    it('should initialize successfully', async () => {
    58→      const context = await clock.initialize();
    59→      
    60→      expect(context).toHaveProperty('audioContext');
    61→      expect(context).toHaveProperty('baseTime');
    62→      expect(context).toHaveProperty('performanceOrigin');
    63→      expect(AudioContext).toHaveBeenCalledOnce();
    64→    });
    65→
    66→    it('should throw error if already initialized', async () => {
    67→      await clock.initialize();
    68→      
    69→      await expect(clock.initialize()).rejects.toThrow('PrecisionClock already initialized');
    70→    });
    71→
    72→    it('should resume suspended audio context', async () => {
    73→      mockAudioContext.state = 'suspended';
    74→      
    75→      await clock.initialize();
    76→      
    77→      expect(mockAudioContext.resume).toHaveBeenCalledOnce();
    78→    });
    79→  });
    80→
    81→  describe('timestamp generation', () => {
    82→    beforeEach(async () => {
    83→      await clock.initialize();
    84→    });
    85→
    86→    it('should generate valid timestamps', () => {
    87→      mockAudioContext.currentTime = 1.234;
    88→      (performance.now as any).mockReturnValue(5678.9);
    89→      
    90→      const timestamp = clock.now();
    91→      
    92→      expect(timestamp).toHaveProperty('audioTime', 1.234);
    93→      expect(timestamp).toHaveProperty('performanceTime', 5678.9);
    94→      expect(timestamp).toHaveProperty('rafTime');
    95→      expect(timestamp).toHaveProperty('monotonic');
    96→      expect(typeof timestamp.monotonic).toBe('number');
    97→    });
    98→
    99→    it('should throw error if not initialized', () => {
   100→      const uninitializedClock = new PrecisionClock();
   101→      
   102→      expect(() => uninitializedClock.now()).toThrow('PrecisionClock not initialized');
   103→    });
   104→
   105→    it('should generate monotonic timestamps', () => {
   106→      const timestamps = [];
   107→      for (let i = 0; i < 10; i++) {
   108→        mockAudioContext.currentTime += 0.001;
   109→        timestamps.push(clock.now());
   110→      }
   111→      
   112→      // Check that monotonic values are increasing
   113→      for (let i = 1; i < timestamps.length; i++) {
   114→        expect(timestamps[i]!.monotonic).toBeGreaterThanOrEqual(timestamps[i - 1]!.monotonic);
   115→      }
   116→    });
   117→  });
   118→
   119→  describe('callback scheduling', () => {
   120→    beforeEach(async () => {
   121→      await clock.initialize();
   122→    });
   123→
   124→    it('should schedule callbacks at specific times', () => {
   125→      const callback = vi.fn();
   126→      const targetTime = 2.0;
   127→      
   128→      clock.scheduleCallback(targetTime, callback);
   129→      
   130→      expect(mockAudioContext.createOscillator).toHaveBeenCalledOnce();
   131→      expect(mockAudioContext.createGain).toHaveBeenCalledOnce();
   132→    });
   133→
   134→    it('should throw error if not initialized', () => {
   135→      const uninitializedClock = new PrecisionClock();
   136→      
   137→      expect(() => {
   138→        uninitializedClock.scheduleCallback(1.0, () => {});
   139→      }).toThrow('PrecisionClock not initialized');
   140→    });
   141→  });
   142→
   143→  describe('frame callbacks', () => {
   144→    beforeEach(async () => {
   145→      await clock.initialize();
   146→    });
   147→
   148→    it('should register and call frame callbacks', () => {
   149→      const callback = vi.fn();
   150→      
   151→      const unsubscribe = clock.onFrame(callback);
   152→      
   153→      expect(typeof unsubscribe).toBe('function');
   154→      expect(requestAnimationFrame).toHaveBeenCalled();
   155→    });
   156→
   157→    it('should unsubscribe frame callbacks', () => {
   158→      const callback = vi.fn();
   159→      
   160→      const unsubscribe = clock.onFrame(callback);
   161→      unsubscribe();
   162→      
   163→      // Should not call callback after unsubscribe
   164→      // This is tested implicitly through RAF mock behavior
   165→    });
   166→  });
   167→
   168→  describe('precision estimation', () => {
   169→    beforeEach(async () => {
   170→      await clock.initialize();
   171→    });
   172→
   173→    it('should estimate timing precision', () => {
   174→      // Create a sequence of values that will produce a non-zero minimum
   175→      const values = [1000.0, 1000.1, 1000.2, 1000.3, 1000.05, 1000.15];
   176→      let callCount = 0;
   177→      (performance.now as any).mockImplementation(() => {
   178→        const value = values[callCount % values.length];
   179→        callCount++;
   180→        return value;
   181→      });
   182→      
   183→      const precision = clock.getPrecisionEstimate();
   184→      
   185→      expect(typeof precision).toBe('number');
   186→      expect(precision).toBeGreaterThan(0);
   187→    });
   188→
   189→    it('should detect high-precision availability', () => {
   190→      const available = clock.isHighPrecisionAvailable();
   191→      
   192→      expect(typeof available).toBe('boolean');
   193→      expect(available).toBe(true);
   194→    });
   195→  });
   196→
   197→  describe('cleanup', () => {
   198→    it('should clean up resources on destroy', async () => {
   199→      await clock.initialize();
   200→      
   201→      await clock.destroy();
   202→      
   203→      expect(mockAudioContext.close).toHaveBeenCalledOnce();
   204→      expect(cancelAnimationFrame).toHaveBeenCalled();
   205→    });
   206→
   207→    it('should handle destroy without initialization', async () => {
   208→      await expect(clock.destroy()).resolves.not.toThrow();
   209→    });
   210→  });
   211→
   212→  describe('error handling', () => {
   213→    it('should handle AudioContext creation failure', async () => {
   214→      const originalAudioContext = global.AudioContext;
