import type { PrecisionClock } from '@psyforge/timing';

export interface DeviceCapabilities {
  readonly canDetectHotplug: boolean;
  readonly supportsHighPrecisionTiming: boolean;
  readonly maxSampleRate?: number;
  readonly supportedFormats?: string[];
  readonly hasOrientationSupport?: boolean;
  readonly hasPressureSupport?: boolean;
}

export interface DeviceEvent<T = any> {
  readonly timestamp: number;
  readonly type: string;
  readonly deviceId: string;
  readonly data: T;
}

export abstract class Device {
  protected readonly clock: PrecisionClock;
  protected _isConnected: boolean = false;
  protected _capabilities: DeviceCapabilities;
  protected eventListeners: Map<string, Set<(event: DeviceEvent) => void>> =
    new Map();

  constructor(
    public readonly id: string,
    protected readonly type: string,
    capabilities: DeviceCapabilities,
    clock: PrecisionClock,
  ) {
    this.clock = clock;
    this._capabilities = capabilities;
  }

  get isConnected(): boolean {
    return this._isConnected;
  }

  get capabilities(): DeviceCapabilities {
    return { ...this._capabilities };
  }

  get deviceType(): string {
    return this.type;
  }

  abstract initialize(): Promise<void>;
  abstract cleanup(): Promise<void>;
  abstract detectCapabilities(): Promise<DeviceCapabilities>;

  addEventListener<T = any>(
    eventType: string,
    callback: (event: DeviceEvent<T>) => void,
  ): void {
    if (!this.eventListeners.has(eventType)) {
      this.eventListeners.set(eventType, new Set());
    }
    this.eventListeners
      .get(eventType)!
      .add(callback as (event: DeviceEvent) => void);
  }

  removeEventListener<T = any>(
    eventType: string,
    callback: (event: DeviceEvent<T>) => void,
  ): void {
    const listeners = this.eventListeners.get(eventType);
    if (listeners) {
      listeners.delete(callback as (event: DeviceEvent) => void);
      if (listeners.size === 0) {
        this.eventListeners.delete(eventType);
      }
    }
  }

  protected emitEvent<T = any>(eventType: string, data: T): void {
    const listeners = this.eventListeners.get(eventType);
    if (listeners && listeners.size > 0) {
      const event: DeviceEvent<T> = {
        timestamp: Number(this.clock.now()),
        type: eventType,
        deviceId: this.id,
        data,
      };

      listeners.forEach((callback) => {
        try {
          callback(event);
        } catch (error) {
          console.error(
            `Error in device event listener for ${eventType}:`,
            error,
          );
        }
      });
    }
  }

  protected setConnected(connected: boolean): void {
    if (this._isConnected !== connected) {
      this._isConnected = connected;
      this.emitEvent(connected ? 'connected' : 'disconnected', { connected });
    }
  }
}

