  private readonly _clock: PrecisionClock;
  private readonly _options: Required<SchedulerOptions>;

  private _taskQueue: ScheduledTask[] = [];
  private _runningTasks: Set<Task> = new Set();
  private _timelines: Set<Timeline> = new Set();
  private _isRunning: boolean = false;
  private _frameHandle: number | null = null;
  private _frameNumber: number = 0;

  // Performance tracking
  private _metrics: SchedulerMetrics = {
    tasksExecuted: 0,
    lateExecutions: 0,
    averageTimingError: 0,
    maxTimingError: 0,
    queueLength: 0,
    frameRate: 0,
    cpuUsage: 0
  };
  private _timingErrors: number[] = [];
  private _frameStartTime: number = 0;

  constructor(options: SchedulerOptions = {}) {
    this._options = {
      maxTasksPerFrame: options.maxTasksPerFrame ?? 10,
      frameTimeBudget: options.frameTimeBudget ?? 8, // 8ms for 120fps headroom
      useHighPrecisionTiming: options.useHighPrecisionTiming ?? true,
      timingTolerance: options.timingTolerance ?? 2, // 2ms tolerance
      allowPreemption: options.allowPreemption ?? true
    };

    this._clock = new PrecisionClock();
  }

